#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define _WIN32_WINNT   0x0500
#define WIN32_LEAN_AND_MEAN

#include <winsock2.h>
#include <windows.h>
#include <tlhelp32.h>

#pragma comment(lib, "ws2_32.lib")

int main(int argc, char* argv[]) {
    WSADATA wsa;
    SOCKET sock;
    struct sockaddr_in addr;
    unsigned short lport = atoi(argv[2]);
    char *lhost = argv[1];

    if (argc != 3) {
        printf("Usage: %s <LHOST> <LPORT>\n", argv[0]);
        return 1;
    }

    // Initialize winsock
    WSAStartup(MAKEWORD(2, 2), &wsa);

    // Create socket
    sock = WSASocket(AF_INET, SOCK_STREAM, IPPROTO_TCP, NULL, (unsigned int)NULL, (unsigned int)NULL);
    if (sock == INVALID_SOCKET) {
        perror("WSASocket");
        WSACleanup();
        return 1;
    }

    // Resolve LHOST to an IP address
    struct hostent *he;
    he = gethostbyname(lhost);
    if (he == NULL || he->h_length == 0) {
        printf("Failed to resolve hostname\n");
        closesocket(sock);
        WSACleanup();
        return 1;
    }
    memcpy(&addr.sin_addr, he->h_addr_list[0], he->h_length);

    // Setup socket options
    int optval = 1;
    setsockopt(sock, SOL_SOCKET, SO_REUSEADDR, (char*)&optval, sizeof(optval));

    // Bind and listen on the specified port
    addr.sin_family = AF_INET;
    addr.sin_port = htons(lport);
    bind(sock, (struct sockaddr*)&addr, sizeof(addr));
    listen(sock, SOMAXCONN);

    // Get list of processes
    PROCESSENTRY32 pe;
    HANDLE hSnapshot, hProc;

    hSnapshot = CreateToolhelp32Snapshot(TH32CS_SNAPPROCESS, 0);
    pe.dwSize = sizeof(PROCESSENTRY32);

    // Check if process is running as SYSTEM
    while (Process32Next(hSnapshot, &pe)) {
        if (!strcmp(pe.szExeFile, "System")) {
            break;
        }
    }

    if (pe.th32ParentProcessID == 0) {
        printf("Current process is not running as SYSTEM.\n");
        CloseHandle(hSnapshot);
        closesocket(sock);
        WSACleanup();
        return 1;
    } else {
        printf("Current process is running as SYSTEM.\n");
        CloseHandle(hSnapshot);
        closesocket(sock);
        WSACleanup();
        return 0;
    }

}